  '[{"label": "مقرر منهج الدعوة النبوية — المسارات التعليمية", "url": "/learning/paths/dawah"}, {"label": "السيرة النبوية — صفحة مرجعية شاملة", "url": "/seerah"}, {"label": "الرحيق المختوم — المكتبة", "url": "/library/book-raheeq"}]'::jsonb,
  '[{"question": "هل مرحلة الدعوة السرية أمر واجب التكرار في كل زمان؟", "answer": "لا؛ هذه تطبيق تاريخي لمرحلة بعينها اقتضتها ظروف مكة آنذاك، وليست نصّاً قرآنياً ثابتاً يُلزَم بتكراره حرفياً. الثابت هو الأصول الثلاثة (الحكمة والموعظة الحسنة والجدال بالتي هي أحسن) لا شكل التطبيق التاريخي بعينه."}, {"question": "ما الفرق بين الحكمة والموعظة الحسنة والجدال بالتي هي أحسن؟", "answer": "الحكمة وضع الأمر في موضعه المناسب بحسب حال المخاطَب وزمانه، والموعظة الحسنة الترغيب والترهيب بأسلوب ليّن يلامس القلب، والجدال بالتي هي أحسن الحوار العقلي المهذَّب مع من يحتاج إقناعاً منطقياً — والداعية الحكيم يختار الأداة المناسبة لكل حال."}, {"question": "لماذا تغيّر أسلوب الدعوة بعد الهجرة؟", "answer": "لأن الهجرة أتاحت للمسلمين كياناً ومجتمعاً مستقلاً بعد أن كانوا أفراداً مضطهَدين وسط عداء قريش، فتوسّعت أدوات الدعوة العملية المتاحة، لكن الأصول القرآنية للمنهج نفسها لم تتغيّر."}]'::jsonb,
  false
